class PageTable:
 def __init__(self, size):
 self.size = size
 self.table = [None] * size

 def isValid(self, pageNumber):
 return self.table[pageNumber] is not None

 def getPage(self, pageNumber):
 if self.isValid(pageNumber):
 return self.table[pageNumber]
 else:
 raise Exception('Page fault')

# Create a page table with 10 entries
pageTable = PageTable(10)

# Set a page as valid
pageTable.table[5] = 'Frame 5'

# Try to access a valid page
try:
 print(pageTable.getPage(5))
except Exception as e:
 print(e)

# Try to access an invalid page
try:
 print(pageTable.getPage(3))
except Exception as e:
 print(e)

#include <stdio.h>

#define PAGE_TABLE_SIZE 10

typedef struct {
 int valid;
 char* frameNumber;
} PageTableEntry;

PageTableEntry pageTable[PAGE_TABLE_SIZE];

int isValid(int pageNumber) {
 return pageTable[pageNumber].valid;
}

char* getPage(int pageNumber) {
 if (isValid(pageNumber)) {
 return pageTable[pageNumber].frameNumber;
 } else {
 printf('Page fault');
 return NULL;
 }
}

int main() {
 // Initialize page table
 for (int i = 0; i < PAGE_TABLE_SIZE; i++) {
 pageTable[i].valid = 0;
 pageTable[i].frameNumber = NULL;
 }

 // Set a page as valid
 pageTable[5].valid = 1;
 pageTable[5].frameNumber = 'Frame 5';

 // Try to access a valid page
 printf('%s', getPage(5));

 // Try to access an invalid page
 printf('%s', getPage(3));

 return 0;
}
